// Package imports:
import 'package:collection/collection.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

enum FabState {
  available,
  needsSubscription,
  unavailable,
}

FabState useFabState({
  required Session session,
  required String teamId,
  required bool canSubscribe,
}) {
  final ref = useWidgetRef();
  final userId = ref.watch(profileStorageProvider).getUserId();
  final accessibleContents =
      ref.watch(userAccessibleContentsControllerProvider);
  final teamList = ref.watch(teamListControllerProvider);

  final isRecordingAvailable = teamList.fold(
    loading: () => null,
    error: (_) => null,
    data: (teams) {
      final team = teams.where((team) => team.id == teamId).firstOrNull;
      if (team == null) {
        return null;
      }

      if (!session.isVideoUploadableByUser(userId, accessibleContents)) {
        return false;
      }

      return team.canAnalyzeBall;
    },
  );

  // Premium プラン契約中かつボール解析が残っていない場合は
  // サブスクリプションページへ遷移させない
  // (canSubscribe が true の時点で isSingleUserTeam は保証されている)
  final shouldBlockSubscriptionNavigation = teamList.fold(
    loading: () => false,
    error: (_) => false,
    data: (teams) {
      final team = teams.where((team) => team.id == teamId).firstOrNull;
      if (team == null) return false;

      return team.teamPlan?.plan?.planType == PlanType.premium;
    },
  );

  if (isRecordingAvailable == true) {
    return FabState.available;
  } else if (isRecordingAvailable == false && canSubscribe) {
    // Premium プラン + ボールゼロの場合は遷移させない
    if (shouldBlockSubscriptionNavigation) {
      return FabState.unavailable;
    }
    return FabState.needsSubscription;
  } else {
    return FabState.unavailable;
  }
}

// Package imports:

// Package imports:
import 'package:flutter_test/flutter_test.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/item.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/models/utils/now_provider.dart';

// ========================================
// テストヘルパー関数
// ========================================

/// 共通で使用する定数
const id = '00000000-0000-4000-8000-000000000000';
const teamPlanId = '77777777-0003-0001-0000-000000000001';
const teamPlanId2 = '77777777-0003-0001-0000-000000000002';
const name = 'test name';
const ownerUserId = '00000000-0000-4000-8000-000000000001';
const imageUrl = 'https://example.test/image.jpg';
const presignedImageUrl = 'https://example.test/image.jpg?presigned';

/// テストで使用する日時を返す
DateTime now() => DateTime.now();
DateTime createdAt() => now().subtract(const Duration(days: 1));
DateTime updatedAt() => now().subtract(const Duration(days: 1));

/// 標準的な Plan を作成
Plan createPlan({
  String planId = '2',
  String planName = 'Test plan',
  int maxBalls = 100,
  int maxAiCoachs = 50,
}) {
  return Plan(
    id: planId,
    name: planName,
    description: 'Test description',
    type: 1,
    maxBalls: maxBalls,
    maxAiCoachs: maxAiCoachs,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
  );
}

/// TeamPlan を作成
TeamPlan createTeamPlan({
  String? id = teamPlanId,
  String? teamId = id,
  String planId = '2',
  DateTime? startDate,
  DateTime? endDate,
  int currentUsage = 0,
  int currentAiCoachUsage = 0,
  bool isActive = true,
  bool isPendingActivation = false,
  Plan? plan,
}) {
  return TeamPlan(
    id: id,
    teamId: teamId,
    planId: planId,
    startDate: startDate ?? now().subtract(const Duration(days: 10)),
    endDate: endDate ?? now().add(const Duration(days: 40)),
    currentUsage: currentUsage,
    currentAiCoachUsage: currentAiCoachUsage,
    isActive: isActive,
    isPendingActivation: isPendingActivation,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
    plan: plan,
  );
}

/// Team を作成
Team createTeam({
  String? teamId = id,
  String? teamName = name,
  String? ownerId = ownerUserId,
  TeamPlan? teamPlan,
  TeamPlan? nextTeamPlan,
  Item? item,
}) {
  return Team(
    id: teamId,
    name: teamName,
    ownerUserId: ownerId,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
    imageUrl: imageUrl,
    teamPlan: teamPlan,
    nextTeamPlan: nextTeamPlan,
    presignedImageUrl: presignedImageUrl,
    item: item,
  );
}

// ========================================
// テストケース
